{
  "recipes": [
    {
      "name": "Authentic Gong Bao Ji Ding (Kung Pao Chicken)",
      "instructions": [
        "Cut the chicken breasts into 1.5cm cubes. Marinate with a pinch of salt, 1 teaspoon of light soy sauce, 1 teaspoon of Shaoxing rice wine, and 1 teaspoon of cornstarch mixed with a tablespoon of water.",
        "Prepare the sauce by mixing Chinkiang vinegar, light soy sauce, sugar, cornstarch, and a tablespoon of water in a small bowl until the sugar is fully dissolved.",
        "Cut the spring onions into whites and greens; we will use the white and light green parts cut into 1.5cm rounds.",
        "Heat cooking oil in a wok over medium-low heat. Add Sichuan peppercorns and dried red chilies, frying until fragrant and the chilies turn dark red (do not burn).",
        "Add minced ginger and garlic, stir-fry briefly, then turn the heat to high, add the marinated chicken cubes, and stir-fry until they turn white.",
        "Toss in the spring onion rounds and stir-fry for 1 minute.",
        "Give the sauce bowl a quick stir, pour it into the wok, and stir-fry rapidly until the sauce thickens and coats the chicken.",
        "Stir in the roasted peanuts, mix well, and serve immediately."
      ],
      "required_ingredients": [
        {
          "name": "chicken breasts",
          "amount": "300g"
        },
        {
          "name": "spring onions",
          "amount": "4 stalks"
