    {
      "name": "Authentic Tomato Stir-Fried Eggs (番茄炒蛋)",
      "instructions": [
        "Beat the eggs in a bowl with a pinch of salt and a dash of white pepper powder.",
        "Heat 1.5 tablespoons of vegetable oil in a wok over medium-high heat. Pour in the beaten eggs and scramble quickly until they are puffed and softly set, then immediately remove them from the wok and set aside.",
        "Add the remaining vegetable oil to the wok. Add the white parts of the chopped scallions and sauté for 10 seconds until fragrant.",
        "Add the halved cherry tomatoes to the wok. Stir-fry, pressing them gently with your spatula to release their juices, until they soften and form a saucy consistency (about 3-4 minutes).",
        "Season the tomatoes with sugar and salt.",
        "Return the scrambled eggs to the wok, tossing quickly for 30 seconds to combine and let the eggs absorb the tomato juices.",
        "Turn off the heat, drizzle with sesame oil, and garnish with the green parts of the scallions before serving hot."
      ],
      "required_ingredients": [
        {
          "name": "large free range eggs",
          "amount": "3"
        },
        {
          "name": "cherry tomatoes",
          "amount": "200g (halved)"
        },
        {
